={{    
  time = $json.created_at.slice(11, 16),   
  user = $json.person?.full_name ?? "Unknown",   
  channel = $json.channel?.name ?? "Unknown",   
  message = $json.message.replace(/[\r\n]+/g, " "),    

  '<b>' + time + ' ' + user + ' (' + channel + ')' + ':</b><br/>'  
  + message + "<br/><br/>" 
}}

